module lfsr_8bit(  
    input clk,  
    input reset,  
    output reg lfsr_out  
);  
    reg [7:0] unused_lfsr;  
    wire feedback;  

    // Feedback polynomial: x^8 + x^6 + x^5 + x^4 + 1  
    assign feedback = unused_lfsr[7] ^ unused_lfsr[5] ^ unused_lfsr[4] ^ unused_lfsr[6];  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_lfsr <= 8'b1; // Initialize to a non-zero value  
        end else begin  
            unused_lfsr <= {unused_lfsr[6:0], feedback};  
        end  
    end  

    always @(posedge clk) begin  
        lfsr_out <= unused_lfsr[7];  
    end  
endmodule
